func protoToDecision(d *decisionpb.Decision) *model.Decision {
	if d == nil {
		return nil
	}
	return &model.Decision{
		ID:              d.Id,
		PaymentEventID:  d.PaymentEventId,
		TenantID:        d.TenantId,
		Outcome:         mapOutcome(d.Outcome),
		ReasonCodes:     d.ReasonCodes,
		ConfidenceScore: d.ConfidenceScore,
		Overridden:      d.Overridden,
		LatencyMs:       int(d.LatencyMs),
		CreatedAt:       tsToTime(d.CreatedAt),
	}
}

func protoToCase(c *casemanagementpb.Case) *model.Case {
	if c == nil {
		return nil
	}
	return &model.Case{
		ID:             c.Id,
		DecisionID:     c.DecisionId,
		TenantID:       c.TenantId,
		AssigneeID:     c.AssigneeId,
		Status:         mapCaseStatus(c.Status),
		Priority:       mapCasePriority(c.Priority),
		PaymentEventID: c.PaymentEventId,
		Outcome:        c.Outcome,
		SLADeadline:    tsToTime(c.SlaDeadline),
		CreatedAt:      tsToTime(c.CreatedAt),
		UpdatedAt:      tsToTime(c.UpdatedAt),
	}
}

func protoToWorkflowTemplate(tmpl *workflowpb.WorkflowTemplate) *model.WorkflowTemplate {
	if tmpl == nil {
		return nil
	}
	transitions := make([]*model.WorkflowTransition, len(tmpl.Transitions))
	for i, t := range tmpl.Transitions {
		guards := make([]*model.WorkflowGuard, len(t.Guards))
		for j, g := range t.Guards {
			guards[j] = &model.WorkflowGuard{
				Type:      mapGuardType(g.Type),
				Role:      g.Role,
				Condition: g.Condition,
			}
		}
		transitions[i] = &model.WorkflowTransition{
			FromState:    t.FromState,
			ToState:      t.ToState,
			RequiredRole: t.RequiredRole,
			Guards:       guards,
		}
	}
	return &model.WorkflowTemplate{
		ID:          tmpl.Id,
		TenantID:    tmpl.TenantId,
		Name:        tmpl.Name,
		Version:     int(tmpl.Version),
		States:      tmpl.States,
		Transitions: transitions,
		CreatedAt:   tsToTime(tmpl.CreatedAt),
		UpdatedAt:   tsToTime(tmpl.UpdatedAt),
	}
}

func protoToRule(r *rulesengine.Rule) *model.Rule {
	if r == nil {
		return nil
	}
	return &model.Rule{
		ID:        r.Id,
		TenantID:  r.TenantId,
		Name:      r.Name,
		Version:   int(r.Version),
		Action:    mapRuleAction(r.Action),
		Priority:  int(r.Priority),
		Enabled:   r.Enabled,
		CreatedAt: tsToTime(r.CreatedAt),
		UpdatedAt: tsToTime(r.UpdatedAt),
	}
}

func protoToTenant(t *tenantpb.Tenant) *model.Tenant {
	if t == nil {
		return nil
	}
	cfg := &model.TenantConfig{}
	if t.Config != nil {
		flags := make([]*model.FeatureFlag, len(t.Config.FeatureFlags))
		for i, f := range t.Config.FeatureFlags {
			flags[i] = &model.FeatureFlag{
				Key:               f.Key,
				Enabled:           f.Enabled,
				RolloutPercentage: int(f.RolloutPercentage),
			}
		}
		cfg = &model.TenantConfig{
			RuleSetID:          t.Config.RuleSetId,
			WorkflowTemplateID: t.Config.WorkflowTemplateId,
			FeatureFlags:       flags,
			Version:            int(t.Config.Version),
		}
	}
	return &model.Tenant{
		ID:        t.Id,
		Name:      t.Name,
		Status:    mapTenantStatus(t.Status),
		CreatedAt: tsToTime(t.CreatedAt),
		Config:    cfg,
	}
}

