// ══════════════════════════════════════════════════════════════════════════════
// UTILITY HELPERS
// ══════════════════════════════════════════════════════════════════════════════

func tsToTime(ts interface{ AsTime() time.Time }) time.Time {
	if ts == nil {
		return time.Time{}
	}
	return ts.AsTime()
}

func derefStr(s *string, fallback string) string {
	if s != nil {
		return *s
	}
	return fallback
}

func derefInt(i *int, fallback int) int {
	if i != nil {
		return *i
	}
	return fallback
}

func withAttr(key, value string) otelmetric.AddOption {
	return otelmetric.WithAttributes(attribute.String(key, value))
}



